head.b:skin:
/*=======================================
  CINEMA DARK V2 - Blogger Template
  ysflix-inspired Movie Theme
  Version: 2.0
=======================================*/

:root {
  --bg-primary: #0f1117;
  --bg-secondary: #161922;
  --bg-card: #1c1f2e;
  --bg-card-hover: #252940;
  --bg-header: #0f1117;
  --bg-input: #1c1f2e;
  --text-primary: #ffffff;
  --text-secondary: #8b92a5;
  --text-muted: #5a6178;
  --accent: #22c55e;
  --accent-hover: #16a34a;
  --star: #fbbf24;
  --border: #2a2d3e;
  --radius: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;
  --shadow: 0 4px 15px rgba(0,0,0,0.3);
  --transition: all 0.25s ease;
  --max-width: 1100px;
}

* { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior:smooth; }
body {
  font-family:'Inter',-apple-system,BlinkMacSystemFont,sans-serif;
  background:var(--bg-primary);
  color:var(--text-primary);
  line-height:1.6;
  overflow-x:hidden;
}
a { text-decoration:none; color:inherit; transition:var(--transition); }
a:hover { color:var(--accent); }
img { max-width:100%; height:auto; display:block; }
ul,ol { list-style:none; }
::selection { background:var(--accent); color:#fff; }
::-webkit-scrollbar { width:6px; }
::-webkit-scrollbar-track { background:var(--bg-primary); }
::-webkit-scrollbar-thumb { background:var(--bg-card); border-radius:3px; }
::-webkit-scrollbar-thumb:hover { background:var(--accent); }

.container { max-width:var(--max-width); margin:0 auto; padding:0 16px; }

/* === Header === */
.site-header {
  background:var(--bg-header);
  border-bottom:1px solid var(--border);
  padding:14px 0;
  position:sticky;
  top:0;
  z-index:1000;
}
.header-inner {
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:20px;
}
.logo a {
  display:flex;
  align-items:center;
  gap:8px;
  font-size:22px;
  font-weight:800;
  color:var(--accent);
  letter-spacing:-0.5px;
}
.logo a i { font-size:24px; }
.header-search {
  flex:1;
  max-width:420px;
}
.search-box {
  display:flex;
  align-items:center;
  background:var(--bg-input);
  border:1px solid var(--border);
  border-radius:50px;
  overflow:hidden;
}
.search-box:focus-within { border-color:var(--accent); }
.search-box input {
  flex:1;
  background:transparent;
  border:none;
  padding:10px 18px;
  color:var(--text-primary);
  font-family:inherit;
  font-size:13px;
  outline:none;
}
.search-box input::placeholder { color:var(--text-muted); }
.search-box button {
  background:var(--accent);
  border:none;
  padding:10px 16px;
  color:#fff;
  cursor:pointer;
  font-size:13px;
}
.search-box button:hover { background:var(--accent-hover); }
.header-right {
  display:flex;
  align-items:center;
  gap:14px;
}
.header-right a,.header-right button {
  color:var(--text-secondary);
  font-size:18px;
  background:none;
  border:none;
  cursor:pointer;
  transition:var(--transition);
}
.header-right a:hover,.header-right button:hover { color:var(--accent); }
.mobile-menu-btn { display:none; }

/* === Navigation === */
.site-nav {
  background:var(--bg-secondary);
  border-bottom:1px solid var(--border);
  overflow-x:auto;
}
.site-nav::-webkit-scrollbar { height:0; }
.nav-list { display:flex; align-items:center; }
.nav-list li a {
  display:flex;
  align-items:center;
  gap:6px;
  padding:12px 16px;
  color:var(--text-secondary);
  font-size:13px;
  font-weight:500;
  white-space:nowrap;
  border-bottom:2px solid transparent;
  transition:var(--transition);
}
.nav-list li a:hover,
.nav-list li a.active {
  color:var(--accent);
  border-bottom-color:var(--accent);
}
.nav-list li a i { font-size:12px; }

/* === Section Header === */
.section-header {
  display:flex;
  align-items:center;
  justify-content:space-between;
  margin-bottom:18px;
  padding-bottom:10px;
  border-bottom:1px solid var(--border);
}
.section-header h2 {
  font-size:18px;
  font-weight:700;
  display:flex;
  align-items:center;
  gap:8px;
}
.section-header h2 i { color:var(--accent); font-size:16px; }
.section-header a {
  font-size:13px;
  font-weight:600;
  color:var(--accent);
  background:rgba(34,197,94,0.1);
  padding:6px 16px;
  border-radius:50px;
  border:1px solid rgba(34,197,94,0.3);
}
.section-header a:hover { background:var(--accent); color:#fff; }

/* === Movie Grid Cards (ysflix style) === */
.movies-section { padding:24px 0; }
.movie-grid {
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:18px;
}
.movie-card {
  background:var(--bg-card);
  border-radius:var(--radius-lg);
  overflow:hidden;
  border:1px solid var(--border);
  transition:var(--transition);
  cursor:pointer;
}
.movie-card:hover {
  transform:translateY(-6px);
  box-shadow:var(--shadow);
  border-color:var(--accent);
}
.movie-card:hover .mc-poster img { transform:scale(1.06); }
.mc-poster {
  position:relative;
  aspect-ratio:2/3;
  overflow:hidden;
  background:var(--bg-secondary);
}
.mc-poster img {
  width:100%;
  height:100%;
  object-fit:cover;
  transition:transform 0.4s ease;
}
.mc-rating {
  position:absolute;
  top:8px;
  right:8px;
  background:rgba(0,0,0,0.75);
  backdrop-filter:blur(6px);
  display:flex;
  align-items:center;
  gap:4px;
  padding:4px 9px;
  border-radius:6px;
  font-size:12px;
  font-weight:700;
}
.mc-rating i { color:var(--star); font-size:10px; }
.mc-quality {
  position:absolute;
  top:8px;
  left:8px;
  background:var(--accent);
  color:#fff;
  padding:2px 8px;
  border-radius:4px;
  font-size:10px;
  font-weight:700;
  letter-spacing:0.3px;
}
.mc-info { padding:12px; }
.mc-title {
  font-size:14px;
  font-weight:600;
  line-height:1.35;
  display:-webkit-box;
  -webkit-line-clamp:2;
  -webkit-box-orient:vertical;
  overflow:hidden;
  margin-bottom:6px;
}
.mc-title a:hover { color:var(--accent); }
.mc-meta {
  display:flex;
  align-items:center;
  gap:8px;
  flex-wrap:wrap;
}
.mc-year {
  font-size:12px;
  color:var(--text-primary);
  font-weight:500;
}
.mc-genre {
  font-size:11px;
  color:var(--text-muted);
}
.mc-genre a { color:var(--text-muted); }
.mc-genre a:hover { color:var(--accent); }
.mc-overlay {
  position:absolute;
  inset:0;
  background:rgba(0,0,0,0.6);
  display:flex;
  align-items:center;
  justify-content:center;
  opacity:0;
  transition:var(--transition);
}
.movie-card:hover .mc-overlay { opacity:1; }
.mc-play {
  width:48px;
  height:48px;
  background:var(--accent);
  border-radius:50%;
  display:flex;
  align-items:center;
  justify-content:center;
  color:#fff;
  font-size:18px;
  box-shadow:0 0 20px rgba(34,197,94,0.4);
}

/* === Pagination === */
.pagination {
  display:flex;
  align-items:center;
  justify-content:center;
  gap:6px;
  padding:30px 0;
}
.pagination a {
  display:flex;
  align-items:center;
  justify-content:center;
  min-width:38px;
  height:38px;
  background:var(--bg-card);
  border:1px solid var(--border);
  border-radius:var(--radius);
  color:var(--text-secondary);
  font-size:13px;
  font-weight:500;
}
.pagination a:hover,.pagination a.active {
  background:var(--accent);
  border-color:var(--accent);
  color:#fff;
}

/* === Genre Tags Section === */
.genre-section { padding:20px 0; }
.genre-list {
  display:flex;
  flex-wrap:wrap;
  gap:8px;
}
.genre-pill {
  display:inline-block;
  padding:7px 16px;
  background:var(--bg-card);
  border:1px solid var(--border);
  border-radius:50px;
  color:var(--text-secondary);
  font-size:12px;
  font-weight:500;
  transition:var(--transition);
}
.genre-pill:hover {
  background:var(--accent);
  border-color:var(--accent);
  color:#fff;
}

/* === Sidebar === */
.main-layout {
  display:grid;
  grid-template-columns:1fr 300px;
  gap:24px;
  padding:24px 0;
}
.sidebar { display:flex; flex-direction:column; gap:20px; }
.sidebar-widget {
  background:var(--bg-card);
  border-radius:var(--radius-lg);
  border:1px solid var(--border);
  overflow:hidden;
}
.sw-title {
  padding:14px 16px;
  font-size:14px;
  font-weight:700;
  border-bottom:1px solid var(--border);
  display:flex;
  align-items:center;
  gap:8px;
}
.sw-title i { color:var(--accent); }
.sw-content { padding:14px; }
.popular-list { display:flex; flex-direction:column; gap:10px; }
.popular-item {
  display:flex;
  gap:10px;
  align-items:flex-start;
}
.popular-num {
  width:26px;
  height:26px;
  background:var(--bg-secondary);
  border-radius:6px;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:12px;
  font-weight:700;
  color:var(--accent);
  flex-shrink:0;
}
.popular-item:nth-child(1) .popular-num { background:var(--accent); color:#fff; }
.popular-item:nth-child(2) .popular-num { background:#3b82f6; color:#fff; }
.popular-item:nth-child(3) .popular-num { background:var(--star); color:#000; }
.popular-text h4 {
  font-size:12px;
  font-weight:500;
  line-height:1.4;
  display:-webkit-box;
  -webkit-line-clamp:2;
  -webkit-box-orient:vertical;
  overflow:hidden;
  margin-bottom:2px;
}
.popular-text h4 a:hover { color:var(--accent); }
.popular-text span { font-size:11px; color:var(--text-muted); }
.sidebar-ad {
  background:var(--bg-secondary);
  border:1px dashed var(--border);
  border-radius:var(--radius-lg);
  padding:20px;
  text-align:center;
}
.sidebar-ad i { font-size:28px; color:var(--text-muted); margin-bottom:8px; }
.sidebar-ad p { color:var(--text-muted); font-size:12px; }

/* === POST DETAIL PAGE (ysflix style) === */
.post-detail { padding:24px 0; }
.pd-wrap { max-width:850px; margin:0 auto; }

/* Breadcrumb */
.pd-breadcrumb {
  display:flex;
  align-items:center;
  gap:6px;
  margin-bottom:20px;
  font-size:12px;
  color:var(--text-muted);
  flex-wrap:wrap;
}
.pd-breadcrumb a { color:var(--accent); }
.pd-breadcrumb i { font-size:8px; }

/* Movie Top Section */
.pd-top {
  display:flex;
  gap:24px;
  margin-bottom:24px;
  background:var(--bg-card);
  border-radius:var(--radius-xl);
  border:1px solid var(--border);
  padding:24px;
}
.pd-poster {
  width:220px;
  min-width:220px;
  aspect-ratio:2/3;
  border-radius:var(--radius);
  overflow:hidden;
  flex-shrink:0;
}
.pd-poster img {
  width:100%;
  height:100%;
  object-fit:cover;
}
.pd-info {
  flex:1;
  display:flex;
  flex-direction:column;
  justify-content:center;
}
.pd-labels {
  display:flex;
  gap:8px;
  margin-bottom:12px;
  flex-wrap:wrap;
}
.pd-label {
  padding:4px 14px;
  background:rgba(34,197,94,0.1);
  border:1px solid rgba(34,197,94,0.3);
  border-radius:50px;
  font-size:11px;
  font-weight:600;
  color:var(--accent);
}
.pd-title {
  font-size:26px;
  font-weight:800;
  line-height:1.3;
  margin-bottom:10px;
}
.pd-rating-row {
  display:flex;
  align-items:center;
  gap:12px;
  margin-bottom:14px;
  flex-wrap:wrap;
}
.pd-stars {
  display:flex;
  align-items:center;
  gap:3px;
}
.pd-stars i { color:var(--star); font-size:14px; }
.pd-rating-num {
  font-size:18px;
  font-weight:700;
  color:var(--star);
}
.pd-meta-items {
  display:flex;
  align-items:center;
  gap:6px;
  color:var(--text-secondary);
  font-size:13px;
  flex-wrap:wrap;
}
.pd-meta-items span { display:flex; align-items:center; gap:4px; }
.pd-meta-items .dot { color:var(--text-muted); }
.pd-meta-items i { color:var(--accent); font-size:12px; }
.pd-director {
  margin-top:10px;
  font-size:13px;
  color:var(--text-secondary);
}
.pd-director strong { color:var(--text-primary); font-weight:600; }

/* Synopsis Section */
.pd-section {
  background:var(--bg-card);
  border-radius:var(--radius-xl);
  border:1px solid var(--border);
  padding:24px;
  margin-bottom:20px;
}
.pd-section-title {
  font-size:16px;
  font-weight:700;
  margin-bottom:16px;
  display:flex;
  align-items:center;
  gap:8px;
  padding-bottom:12px;
  border-bottom:1px solid var(--border);
}
.pd-section-title i { color:var(--accent); }
.pd-section-title .imdb-badge {
  margin-left:auto;
  font-size:12px;
  font-weight:600;
  color:var(--star);
  background:rgba(251,191,36,0.1);
  padding:3px 12px;
  border-radius:50px;
}
.synopsis-text {
  font-size:14px;
  line-height:1.9;
  color:var(--text-secondary);
}
.synopsis-text p { margin-bottom:14px; }

/* Technical Info */
.tech-info {
  display:grid;
  grid-template-columns:repeat(2,1fr);
  gap:10px;
  margin-top:16px;
  padding-top:16px;
  border-top:1px solid var(--border);
}
.tech-row {
  display:flex;
  gap:8px;
  font-size:13px;
}
.tech-row .tl { color:var(--text-muted); min-width:85px; }
.tech-row .tv { color:var(--text-primary); font-weight:500; }

/* Download Table (ysflix style) */
.dl-table-wrap {
  overflow-x:auto;
}
.dl-table {
  width:100%;
  border-collapse:collapse;
  font-size:13px;
}
.dl-table thead th {
  background:var(--bg-secondary);
  padding:10px 14px;
  text-align:left;
  font-weight:600;
  color:var(--text-primary);
  border-bottom:2px solid var(--accent);
  white-space:nowrap;
}
.dl-table tbody td {
  padding:10px 14px;
  border-bottom:1px solid var(--border);
  color:var(--text-secondary);
  white-space:nowrap;
}
.dl-table tbody tr:hover { background:rgba(34,197,94,0.03); }
.dl-table .server-link {
  color:var(--accent);
  font-weight:600;
}
.dl-table .server-link:hover { text-decoration:underline; }

/* Share Buttons */
.share-row {
  display:flex;
  align-items:center;
  gap:8px;
  margin-top:20px;
  padding-top:16px;
  border-top:1px solid var(--border);
}
.share-row span { font-weight:600; font-size:13px; }
.share-btn {
  width:34px;
  height:34px;
  border-radius:50%;
  display:flex;
  align-items:center;
  justify-content:center;
  color:#fff;
  font-size:13px;
  transition:var(--transition);
}
.share-btn:hover { transform:translateY(-2px); opacity:0.9; }
.share-btn.fb { background:#1877f2; }
.share-btn.tw { background:#1da1f2; }
.share-btn.tg { background:#0088cc; }
.share-btn.wa { background:#25d366; }

/* Related Posts */
.related-grid {
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:14px;
  margin-top:14px;
}
.related-card {
  background:var(--bg-card);
  border-radius:var(--radius);
  overflow:hidden;
  border:1px solid var(--border);
  transition:var(--transition);
}
.related-card:hover { border-color:var(--accent); transform:translateY(-3px); }
.related-card-img { aspect-ratio:16/9; overflow:hidden; }
.related-card-img img { width:100%; height:100%; object-fit:cover; transition:var(--transition); }
.related-card:hover .related-card-img img { transform:scale(1.05); }
.related-card-info { padding:10px; }
.related-card-info h4 {
  font-size:12px;
  font-weight:500;
  line-height:1.4;
  display:-webkit-box;
  -webkit-line-clamp:2;
  -webkit-box-orient:vertical;
  overflow:hidden;
}
.related-card-info h4 a:hover { color:var(--accent); }

/* === Comments === */
.comments-section {
  background:var(--bg-card);
  border-radius:var(--radius-lg);
  border:1px solid var(--border);
  padding:20px;
  margin-top:24px;
}
.comments-section h3 {
  font-size:16px;
  font-weight:700;
  margin-bottom:16px;
  display:flex;
  align-items:center;
  gap:8px;
}
.comments-section h3 i { color:var(--accent); }

/* === Footer === */
.site-footer {
  background:var(--bg-secondary);
  border-top:1px solid var(--border);
  padding:30px 0 0;
  margin-top:40px;
}
.footer-grid {
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:24px;
  padding-bottom:24px;
}
.footer-col h4 {
  font-size:14px;
  font-weight:700;
  margin-bottom:14px;
  display:flex;
  align-items:center;
  gap:6px;
}
.footer-col h4 i { color:var(--accent); font-size:13px; }
.footer-about p { color:var(--text-secondary); font-size:12px; line-height:1.8; margin-bottom:12px; }
.footer-social { display:flex; gap:8px; }
.footer-social a {
  width:32px; height:32px;
  background:var(--bg-card);
  border:1px solid var(--border);
  border-radius:50%;
  display:flex; align-items:center; justify-content:center;
  color:var(--text-secondary);
  font-size:12px;
}
.footer-social a:hover { background:var(--accent); border-color:var(--accent); color:#fff; }
.footer-links li { margin-bottom:6px; }
.footer-links li a {
  color:var(--text-secondary); font-size:12px;
  display:flex; align-items:center; gap:6px;
}
.footer-links li a:hover { color:var(--accent); padding-left:4px; }
.footer-links li a i { font-size:6px; color:var(--accent); }
.footer-contact li {
  display:flex; align-items:flex-start; gap:8px;
  margin-bottom:8px; color:var(--text-secondary); font-size:12px;
}
.footer-contact li i { color:var(--accent); margin-top:2px; }
.footer-bottom {
  border-top:1px solid var(--border);
  padding:14px 0;
  text-align:center;
}
.footer-bottom p { color:var(--text-muted); font-size:11px; }
.footer-bottom a { color:var(--accent); font-weight:500; }

/* === Back to Top === */
.back-top {
  position:fixed; bottom:24px; right:24px;
  width:40px; height:40px;
  background:var(--accent);
  border-radius:50%;
  display:flex; align-items:center; justify-content:center;
  color:#fff; font-size:14px;
  cursor:pointer;
  opacity:0; visibility:hidden;
  transition:var(--transition);
  z-index:999;
}
.back-top.visible { opacity:1; visibility:visible; }
.back-top:hover { background:var(--accent-hover); transform:translateY(-3px); }

/* === Blogger Overrides === */
.post-outer,.post { background:none!important; border:none!important; padding:0!important; }
.post-body img { background:none; border:none; padding:0; border-radius:var(--radius); }
#comments { background:none; }
.widget ul { list-style:none; }
.blog-posts .post-outer-container { margin-bottom:0; }
.status-msg-wrap { margin:12px 0; padding:10px 14px; background:rgba(34,197,94,0.1); border:1px solid rgba(34,197,94,0.3); border-radius:var(--radius); color:var(--accent); font-size:13px; }

/* === Animations === */
@keyframes fadeUp { from{opacity:0;transform:translateY(16px)} to{opacity:1;transform:translateY(0)} }
.movie-card { animation:fadeUp 0.4s ease forwards; }
.movie-card:nth-child(2){animation-delay:.05s}
.movie-card:nth-child(3){animation-delay:.1s}
.movie-card:nth-child(4){animation-delay:.15s}
.movie-card:nth-child(5){animation-delay:.2s}
.movie-card:nth-child(6){animation-delay:.25s}
.movie-card:nth-child(7){animation-delay:.3s}
.movie-card:nth-child(8){animation-delay:.35s}
.movie-card:nth-child(9){animation-delay:.4s}

/* === Responsive === */
@media(max-width:1024px){
  .main-layout{grid-template-columns:1fr}
  .sidebar{display:grid;grid-template-columns:repeat(2,1fr)}
  .movie-grid{grid-template-columns:repeat(2,1fr)}
  .footer-grid{grid-template-columns:repeat(2,1fr)}
}
@media(max-width:768px){
  .mobile-menu-btn{display:block}
  .header-search{order:3;max-width:100%;width:100%;margin-top:10px}
  .header-inner{flex-wrap:wrap}
  .site-nav{display:none}
  .site-nav.active{display:block}
  .nav-list{flex-direction:column}
  .nav-list li a{border-bottom:1px solid var(--border);width:100%;padding:11px 16px}
  .movie-grid{grid-template-columns:repeat(2,1fr);gap:12px}
  .sidebar{grid-template-columns:1fr}
  .footer-grid{grid-template-columns:1fr}
  .pd-top{flex-direction:column;align-items:center;text-align:center}
  .pd-poster{width:180px;min-width:180px}
  .pd-rating-row{justify-content:center}
  .pd-labels{justify-content:center}
  .pd-director{justify-content:center}
  .tech-info{grid-template-columns:1fr}
  .related-grid{grid-template-columns:repeat(2,1fr)}
  .container{padding:0 12px}
  .pd-title{font-size:20px}
}
@media(max-width:480px){
  .movie-grid{grid-template-columns:repeat(2,1fr);gap:10px}
  .mc-info{padding:10px}
  .mc-title{font-size:12px}
  .mc-genre{font-size:10px}
  .related-grid{grid-template-columns:1fr}
  .dl-table{font-size:11px}
  .dl-table thead th,.dl-table tbody td{padding:8px 10px}
}

body.script:
//
// Back to Top
var backToTop=document.getElementById('backToTop');
if(backToTop){
  window.addEventListener('scroll',function(){
    if(window.pageYOffset>300) backToTop.classList.add('visible');
    else backToTop.classList.remove('visible');
  });
  backToTop.addEventListener('click',function(e){
    e.preventDefault();window.scrollTo({top:0,behavior:'smooth'});
  });
}
// Mobile Menu
var mmb=document.getElementById('mobileMenuBtn');
var sn=document.getElementById('siteNav');
if(mmb&&sn) mmb.addEventListener('click',function(){sn.classList.toggle('active');});
// Year
var ye=document.getElementById('currentYear');
if(ye) ye.textContent=new Date().getFullYear();
// Related Posts
if(document.getElementById('relatedPosts')){
  var lb=document.querySelectorAll('.pd-label');
  if(lb.length>0){
    var furl=lb[0].getAttribute('href');
    if(furl){
      fetch(furl+'?max-results=3&alt=json').then(function(r){return r.json();}).then(function(d){
        var c=document.getElementById('relatedPosts');
        if(d.feed&&d.feed.entry){
          var h='';
          d.feed.entry.forEach(function(e){
            var t=e.title.$t,l='',img='https://via.placeholder.com/400x225/1c1f2e/22c55e?text=Movie';
            e.link.forEach(function(k){if(k.rel==='alternate')l=k.href;});
            if(e.media$thumbnail) img=e.media$thumbnail.url.replace('/s72-c/','/w400-h225-c/');
            if(l&&t) h+='<div class="related-card"><div class="related-card-img"><img alt="'+t+'" src="'+img+'"/></div><div class="related-card-info"><h4><a href="'+l+'">'+t+'</a></h4></div></div>';
          });
          c.innerHTML=h;
        }
      }).catch(function(){});
    }
  }
}
//
